import numpy as np
import pandas as pd
def score_ohlcv(df):
 fields=df[['Open','High','Low','Close','Volume']];nan_missing=float(fields.isna().mean().mean());expected=pd.bdate_range(pd.Timestamp(df.index.min()).normalize(),pd.Timestamp(df.index.max()).normalize()) if len(df) else [];calendar_missing=max(0.0,1-len(pd.DatetimeIndex(df.index).normalize().unique())/max(len(expected),1));missing=max(nan_missing,calendar_missing);returns=df.Close.pct_change().replace([np.inf,-np.inf],np.nan);median=float(returns.median());mad=float((returns-median).abs().median());gap_flags=(returns-median).abs()>max(.20,8*1.4826*mad);gaps=float(gap_flags.mean());stale=float((df.Close.diff().abs()<1e-12).tail(20).mean());volume=df.Volume.astype(float);log_volume=np.log1p(volume.clip(lower=0));volume_mad=float((log_volume-log_volume.median()).abs().median());volume_flags=(volume<=0)|((log_volume-log_volume.median()).abs()>max(3.0,8*1.4826*volume_mad));vol=float(volume_flags.mean());distortion=float(((returns.abs()>.45)&(volume<volume.rolling(20,min_periods=5).median())).mean());invalid=float(((fields[['Open','High','Low','Close']]<=0).any(axis=1)|(df.High<df.Low)).mean());confidence=max(0.,min(1.,1-missing*3-gaps*2-stale-vol-distortion-invalid*3));return {'missing_candle_pct':missing,'gap_anomaly_score':gaps,'volume_anomaly_score':vol,'stale_price_score':stale,'corporate_action_distortion':distortion,'invalid_ohlc_score':invalid,'data_confidence':confidence}
